(async () => {
  if (!window._blobs) window._blobs = {};
  const files = {"MASTER-DEPLOYMENT-GUIDE.md": "", "MASTER-SETUP-GUIDE.md": "", "MILLION-DOLLAR-MOVES.md": "", "MISSING-ANGLES.md": "", "OPS-MANUAL.md": "", "PLATFORM-SETUP-NOW.md": "", "ROUND-14.md": "", "SCALE-EVERYTHING.md": "", "SEARCH-MAGNET.md": "", "SOCCER-EMPIRE.md": "", "THE-FULL-SQUEEZE.md": "", "THE-MASTER.md": ""};
  const results = await Promise.all(Object.entries(files).map(async ([path, content]) => {
    const r = await fetch('https://api.github.com/repos/' + window._owner + '/' + window._repo + '/git/blobs', {
      method: 'POST',
      headers: {'Authorization': 'token ' + window._token, 'Content-Type': 'application/json', 'Accept': 'application/vnd.github.v3+json'},
      body: JSON.stringify({content, encoding: 'base64'})
    });
    const d = await r.json();
    if (d.sha) {
      window._blobs[path] = d.sha;
      return 'OK:' + path;
    } else {
      return 'ERR:' + path + ':' + JSON.stringify(d).substring(0,80);
    }
  }));
  return 'Batch 2/30 done. Files: ' + Object.keys(window._blobs).length + ' | ' + results.filter(r=>r.startsWith('ERR')).join(' ');
})();